#include<cstdio>
#include<algorithm>
#include<set>
#include<map>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
template<typename T> inline void Swap(T&x,T&y){T tmp=x;x=y;y=tmp;}
typedef long long LL;
const int N=2e5+10;int a[N],n,ch[N<<5][2],cnt=1,ql[N<<5],qr[N<<5];
inline void ins(int x,int I)
{
	int p=1;drep(29,0,i)
	{
		int &c=ch[p][x>>i&1];
		if(!c)p=c=++cnt,ql[p]=qr[p]=I;else qr[p=c]=I;
	}
}
inline int qry(int x,int w,int dep)
{
	int ans=0;drep(dep,0,i)
	{
		if(ch[x][w>>i&1])x=ch[x][w>>i&1];
		else x=ch[x][(w>>i&1)^1],ans|=(1<<i);
	}
	return ans;
}
inline LL dfs(int u,int dep=30)
{
	if(ch[u][0]&&ch[u][1])
	{
		bool flag=0;if(ch[u][0]>ch[u][1])flag=1,Swap(ch[u][0],ch[u][1]);
		int mn=1<<30;rep(ql[ch[u][0]],qr[ch[u][0]],i)mn=min(mn,qry(ch[u][1],a[i],dep-2));
		if(flag)Swap(ch[u][0],ch[u][1]); 
		return dfs(ch[u][0],dep-1)+dfs(ch[u][1],dep-1)+(mn|(1<<(dep-1)));
	}
	return ch[u][0]?dfs(ch[u][0],dep-1):(ch[u][1]?dfs(ch[u][1],dep-1):0);
}
int main()
{
	n=read();rep(1,n,i)a[i]=read();
	std::sort(a+1,a+n+1);n=std::unique(a+1,a+n+1)-a-1;
	rep(1,n,i)ins(a[i],i);printf("%lld\n",dfs(1)); 
	
}
